parameters.jsCode:
return [{
  json: {
    user_id: 'boss',
    thread_id: 'k3rn:default',
    message: $input.first().json.chatInput,
    timestamp: new Date().toISOString()
  }
}];

// DEFAULT_RESPONSE — K3rn.labs v0 execution agent
// Params injected by schema: message, sep_context
const msg = typeof message !== 'undefined' ? message : '';
const ctx = typeof sep_context !== 'undefined' ? sep_context : '';

const OPENAI_KEY = $env.OPENAI_API_KEY;
if (!OPENAI_KEY) throw new Error('OPENAI_API_KEY not set — go to n8n Settings > Variables');

const resp = await fetch('https://api.openai.com/v1/chat/completions', {
  method: 'POST',
  headers: {
    'Authorization': `Bearer ${OPENAI_KEY}`,
    'Content-Type': 'application/json'
  },
  body: JSON.stringify({
    model: 'gpt-4o',
    messages: [
      {
        role: 'system',
        content: 'You are K3rn.labs v0 execution agent.\nGiven the user message and the SEP context, produce:\n1) Summary (max 2 sentences)\n2) Answer / first move\n3) ONE next question (only one).\nNo fluff.'
      },
      {
        role: 'user',
        content: `USER: ${msg}\nSEP_CONTEXT_LAST_MESSAGES: ${ctx}`
      }
    ],
    max_tokens: 2000
  })
});

const data = await resp.json();
if (data.error) throw new Error(`OpenAI error: ${data.error.message}`);
return data.choices[0].message.content;

